sequence.script:
// -------------------------------
// Format current date
// -------------------------------
function formatDate(dateObj) {
    return dateObj.toLocaleString("en-US", {
        month: "long",
        day: "2-digit",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
        hour12: true
    });
}

var nowFormatted = formatDate(new Date());

// -------------------------------
// Subject
// -------------------------------
var subject = "Agent Payout Processed Successfully";
mc.setProperty("mail.smtp.subject", subject);
mc.setProperty("Email_Subject", subject);

// -------------------------------
// HTML Body
// -------------------------------
var emailBody =
'<!doctype html>' +
'<html lang="en">' +
'<head>' +
'  <meta charset="utf-8">' +
'  <meta name="viewport" content="width=device-width, initial-scale=1.0" />' +
'  <style>' +
'    body { margin:0; padding:0; font-family:Arial, Helvetica, sans-serif; background:#f4f6f8; color:#333; }' +
'    .container { max-width:700px; margin:20px auto; background:#fff; border-radius:6px; box-shadow:0 2px 6px rgba(0,0,0,0.15); }' +
'    .header { background:#51c210; padding:24px; text-align:center; color:#fff; font-size:26px; font-weight:bold; }' +
'    .body { padding:30px; font-size:15px; line-height:1.6; }' +
'    .footer { padding:20px; text-align:center; font-size:12px; color:#9aa7bf; }' +
'  </style>' +
'</head>' +
'<body>' +
'  <div class="container">' +
'    <div class="header">Agent Payout Processed Successfully</div>' +
'    <div class="body">' +
'      <p>' + nowFormatted + '</p>' +
'      <p>Dear User,</p>' +
'      <p>We hope you are doing well. We are pleased to inform you that your payout for the recent policy transaction has been successfully processed.</p>' +
'      <p>The amount has been credited to your registered bank account. Depending on your bank, it may take a few business days to reflect in your account.</p>' +
'      <p>If you have any questions or need further clarification regarding this payout, please feel free to reach out to our support team.</p>' +
'      <p>Thank you for your continued partnership and contribution.</p>' +
'      <p>Sincerely,<br><strong>Exasure IIC</strong><br>Policy & Customer Support</p>' +
'    </div>' +
'    <div class="footer">' +
'      Exasure IIC | http://localhost:5173/home<br>' +
'      This is an automated message. Please do not reply.' +
'    </div>' +
'  </div>' +
'</body>' +
'</html>';

mc.setProperty("Email_Body", emailBody);
